<template><ion-page><AppHeader :title="editing ? 'Editar Fornecedor' : 'Novo Fornecedor'" back /><ion-content class="vivid-page"><div class="form-page"><AppField v-model="form.name" label="Nome / Razão Social" placeholder="Ex: Logística Brasil LTDA" /><AppField v-model="form.taxId" label="CNPJ / CPF" placeholder="00.000.000/0000-00" /><AppField v-model="form.contactInfo" label="Contato" placeholder="Telefone ou e-mail" /><button class="primary-button" @click="save">{{ editing?'Atualizar':'Cadastrar' }}</button></div></ion-content></ion-page></template>
<script setup lang="ts">import { computed,reactive } from 'vue';import { IonPage,IonContent,toastController,onIonViewWillEnter } from '@ionic/vue';import { useRoute,useRouter } from 'vue-router';import AppHeader from '@/components/AppHeader.vue';import AppField from '@/components/AppField.vue';import { useSuppliersStore } from '@/stores/suppliers';const route=useRoute(),router=useRouter(),store=useSuppliersStore(),form=reactive({name:'',taxId:'',contactInfo:''}),editing=computed(()=>!!route.params.id);onIonViewWillEnter(async()=>{if(!store.items.length)await store.fetch();const item=store.items.find(s=>s.id===route.params.id);if(item)Object.assign(form,item)});const save=async()=>{try{editing.value?await store.update(String(route.params.id),form):await store.create(form);router.replace('/suppliers')}catch{const t=await toastController.create({message:'Erro ao salvar fornecedor',color:'danger',duration:2500});t.present()}};</script>
<style scoped>.form-page{padding:34px 20px}</style>
